class Solution:
    def secondsToRemoveOccurrences(self, s):
        a = list(s)
        t = 0
        while True:
            moved = False
            i = 0
            res = a[:]
            while i < len(a) - 1:
                if a[i] == '0' and a[i + 1] == '1':
                    res[i] = '1'
                    res[i + 1] = '0'
                    moved = True
                    i += 2
                else:
                    i += 1
            a = res
            if not moved:
                break
            t += 1
        return t

